import tarfile
import json

def merge_configs(input_files):
    configs = []

    for f in input_files:
        if f.endswith('.json'):
            with open(f, 'r') as json_file:
                configs.append(json.load(json_file))
        elif f.endswith('.tar.gz'):
            tar = tarfile.open(f, 'r:gz')
            tar.extractall(path="/path-to-extract")

            for member in tar.getmembers():
                if member.name.endswith('.json'):
                    with open(member.name, 'r') as json_file:
                        configs.append(json.load(json_file))

    merged_config = {}
    for c in configs:
        merged_config = {**merged_config, **c}

    return merged_config

if __name__ == '__main__':
    input_files = ['default-config.json', 'user-config.tar.gz', 'env-config.json']
    config = merge_configs(input_files)
    print(json.dumps(config, indent=4))

def is_trivial(s):
    if s == "a":
        return False
    else:
        return True

def palindrome(s):
    if s == s[::-1]:
        if is_trivial(s):
            print("Trivial palindrome")
            return True
        else:
            print("Non-trivial palindrome")
            return True
    else:
        print("Not a palindrome")
        return False

palindrome("abcba")
