import string
import random

def opposite_text(text):
    opposites = string.ascii_lowercase
    rand_opposites = random.sample(opposites, len(opposites))
    mapping = {opposites[i] : rand_opposites[i] for i in range(len(opposites))}

    return ''.join([mapping.get(c, c) for c in text])

text = "the quick brown fox"
print(opposite_text(text))

