import os

def consolidate_images(image_dir):
    os.chdir(image_dir)
    categories = set(os.listdir('.'))

    for category in categories:
        category_path = os.path.join(image_dir, category)
        os.chdir(category_path)

        for filename in os.listdir('.'):
            if filename.endswith('.jpg'):
                new_path = os.path.join(image_dir, category, filename)
                os.replace(filename, new_path)

                with open(filename, 'a') as f:
                    f.write('\nBanned metadata')

        os.chdir('..')

       for cat in categories:
           category_path = os.path.join(image_dir, cat)
           for file in os.listdir(category_path):
               filepath = os.path.join(category_path, file)
               os.chmod(filepath, 0o777)

consolidate_images('images')

