def items():
    return_transaction_items = request.get_json()
    inventory = Inventory()
    total = 0

    for item in return_transaction_items:
        inventory.check_in(item)
        total -= inventory.get_diff_totals(item['sku'], item['qty'])

    transaction = Transaction()
    transaction.total = total
    transaction.commit()

    return {'success': True}

@app.route('/check-in', methods=['POST'])
@app.route('/check-in/<sku>/<int:index>', methods=['PUT'])
def check_in(sku, index=None):
    items = Inventory().list()
    inventory = Inventory()
    if index:
        inventory.check_in(index)
        quantity = inventory.get_item(index).quantity
    else:
        quantity = inventory.sum_qty([i for i in items if i.sku == sku])

    slip = Transaction(
        transaction_id=f'transaction{datetime.datetime.now().strftime("%Y%m%d-%H%M%S")}',
        event='check-in',
        quantity=quantity,
        created_at=datetime.datetime.now(),
        status='ok'
    ).commit()

    return {'transaction_id': slip.transaction_id, 'status': slip.status}

