def get_book_details(book_id):
    client = Elasticsearch(['elasticsearch.example.com:9200'])

    index = "books_public"
    id = book_id

    query = {
        "query": {"match_all": {}},
        "_source": ["id", "title", "description"],
        "size": 1
    }

    resp = client.search(index=index, type='doc', body=query, scroll='2m')

    initial_scroll_id = resp['_scroll_id']
    next_scroll_id = initial_scroll_id

    while True:
        resp = client.scroll(scroll_id=next_scroll_id, scroll='2m')
        hits = resp['hits']['hits']

        if not hits:
            break

        if resp['_type'] == 'book':
            if resp['_id'] == id:
                book = resp['_source']
                return book

        next_scroll_id = resp['_scroll_id']

    return None

